// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {StringUtils} from "./libraries/StringUtils.sol";
import {ReentrancyGuard} from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import {Pausable} from "@openzeppelin/contracts/utils/Pausable.sol";
import {AccessControl} from "@openzeppelin/contracts/access/AccessControl.sol";

interface IHospital {
    function isDoctorOnDuty(address _doctor, address _hospitalAddress) external view returns (bool);
}

contract Doctor is ReentrancyGuard, Pausable, AccessControl {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant DOCTOR_ROLE = keccak256("DOCTOR_ROLE");

    struct DoctorDetails {
        uint256 doctorId;
        string name;
        string specialization;
        string email;
        uint256[] patientIds; // List of patients linked to this doctor
    }

    struct DocumentAccess {
        address patient;
        string ipfsHash;
        string fileName;
        bool hasAccess;
        uint256 grantTime;
        uint256 duration;
        string reason;
        bool isEmergency;
        bool isResolved; // NEW: Alert dismissed?
    }

    mapping(address => uint256) public walletToDoctorId;
    mapping(uint256 => DoctorDetails) public doctors;
    mapping(uint256 => DocumentAccess[]) public doctorAccessList;
    mapping(address => uint256) private _lastAccessTime;
    mapping(address => uint256) private _accessCount;

    uint256 private doctorIdCounter;
    uint256 public constant RATE_LIMIT_WINDOW = 1 hours;
    uint256 public constant MAX_ACCESS_REQUESTS = 10;

    // Hospital Verification
    address public owner;
    address public hospitalContract;

    // --- EVENTS ---
    event AccessRequested(
        address indexed patient,
        address indexed doctor,
        string ipfsHash,
        string fileName,
        uint256 duration,
        string reason
    );
    event AccessGranted(
        address indexed patient,
        address indexed doctor,
        string ipfsHash,
        uint256 grantTime,
        uint256 duration
    );
    event AccessRevoked(
        address indexed patient,
        address indexed doctor,
        string ipfsHash,
        uint256 revokeTime
    );
    event PatientAdded(
        uint256 indexed doctorId,
        uint256 indexed patientId,
        address indexed doctor
    );
    event EmergencyAccessGranted(
        address indexed doctor,
        address indexed patient,
        string ipfsHash,
        string reason,
        uint256 timestamp
    );
    event EmergencyResolved(
        address indexed patient,
        address indexed resolver,
        string ipfsHash,
        uint256 timestamp
    );

    constructor() {
        owner = msg.sender;
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can call this");
        _;
    }

    function setHospitalContract(address _addr) public onlyRole(ADMIN_ROLE) whenNotPaused {
        require(_addr != address(0), "Invalid zero address");
        hospitalContract = _addr;
    }

    function registerDoctor(
        string memory _name,
        string memory _specialization,
        string memory _hospital
    ) public {
        require(walletToDoctorId[msg.sender] == 0, "Doctor already registered");
        doctorIdCounter++;
        walletToDoctorId[msg.sender] = doctorIdCounter;

        DoctorDetails storage newDoctor = doctors[doctorIdCounter];
        newDoctor.doctorId = doctorIdCounter;
        newDoctor.name = _name;
        newDoctor.specialization = _specialization;
        newDoctor.email = _hospital; // Keeping legacy field mapping for now
    }

    function addPatient(uint256 _patientId) public {
        uint256 doctorId = walletToDoctorId[msg.sender];
        require(doctorId != 0, "Doctor not registered");

        bool exists = false;
        for (uint i = 0; i < doctors[doctorId].patientIds.length; i++) {
            if (doctors[doctorId].patientIds[i] == _patientId) {
                exists = true;
                break;
            }
        }
        require(!exists, "Patient already added");

        doctors[doctorId].patientIds.push(_patientId);
        emit PatientAdded(doctorId, _patientId, msg.sender);
    }

    function getDoctorPatients() public view returns (uint256[] memory) {
        uint256 doctorId = walletToDoctorId[msg.sender];
        require(doctorId != 0, "Doctor not registered");
        return doctors[doctorId].patientIds;
    }

    function hasAccessToDocument(
        address _patient,
        string memory _ipfsHash
    ) public view returns (bool) {
        uint256 doctorId = walletToDoctorId[msg.sender];
        require(doctorId != 0, "Doctor not registered");

        DocumentAccess[] memory accessList = doctorAccessList[doctorId];
        for (uint256 i = 0; i < accessList.length; i++) {
            if (
                accessList[i].patient == _patient &&
                keccak256(abi.encodePacked(accessList[i].ipfsHash)) ==
                keccak256(abi.encodePacked(_ipfsHash)) &&
                accessList[i].hasAccess
            ) {
                // Check for expiration
                if (
                    block.timestamp >
                    accessList[i].grantTime + accessList[i].duration
                ) {
                    return false;
                }
                return true;
            }
        }
        return false;
    }

    function requestAccess(
        address _patient,
        string memory _ipfsHash,
        string memory _fileName,
        uint256 _duration,
        string memory _reason
    ) public whenNotPaused nonReentrant {
        uint256 doctorId = walletToDoctorId[msg.sender];
        require(doctorId != 0, "Doctor not registered");

        require(_patient != address(0), "Invalid patient address");
        require(bytes(_ipfsHash).length > 0, "Invalid IPFS hash");
        require(_duration > 0 && _duration <= 365 days, "Invalid duration");

        if (block.timestamp < _lastAccessTime[msg.sender] + RATE_LIMIT_WINDOW) {
            require(_accessCount[msg.sender] < MAX_ACCESS_REQUESTS, "Rate limit exceeded");
            _accessCount[msg.sender]++;
        } else {
            _lastAccessTime[msg.sender] = block.timestamp;
            _accessCount[msg.sender] = 1;
        }

        doctorAccessList[doctorId].push(
            DocumentAccess({
                patient: _patient,
                ipfsHash: _ipfsHash,
                fileName: _fileName,
                hasAccess: false,
                grantTime: 0,
                duration: _duration,
                reason: _reason,
                isEmergency: false,
                isResolved: false
            })
        );

        emit AccessRequested(
            _patient,
            msg.sender,
            _ipfsHash,
            _fileName,
            _duration,
            _reason
        );
    }

    function emergencyBreakGlass(
        address _patient,
        string memory _ipfsHash,
        string memory _fileName,
        string memory _reason,
        address _hospitalAddress
    ) public whenNotPaused nonReentrant {
        uint256 doctorId = walletToDoctorId[msg.sender];
        require(doctorId != 0, "Doctor not registered");
        require(hospitalContract != address(0), "Hospital verification system not set");
        require(_patient != address(0), "Invalid patient address");

        // Verify with Hospital Contract
        bool onDuty = IHospital(hospitalContract).isDoctorOnDuty(msg.sender, _hospitalAddress);
        require(onDuty, "Doctor is not punched in for emergency duty at this hospital");

        doctorAccessList[doctorId].push(
            DocumentAccess({
                patient: _patient,
                ipfsHash: _ipfsHash,
                fileName: _fileName,
                hasAccess: true, // Auto Grant
                grantTime: block.timestamp,
                duration: 24 hours, // Fixed duration for emergency
                reason: _reason,
                isEmergency: true,
                isResolved: false
            })
        );

        emit EmergencyAccessGranted(
            msg.sender,
            _patient,
            _ipfsHash,
            _reason,
            block.timestamp
        );
    }

    function grantAccess(
        address _doctor,
        string memory _ipfsHash,
        uint256 _duration
    ) public {
        uint256 doctorId = walletToDoctorId[_doctor];
        require(doctorId != 0, "Doctor not registered");

        DocumentAccess[] storage accessList = doctorAccessList[doctorId];
        for (uint256 i = 0; i < accessList.length; i++) {
            if (
                accessList[i].patient == msg.sender &&
                keccak256(abi.encodePacked(accessList[i].ipfsHash)) ==
                keccak256(abi.encodePacked(_ipfsHash))
            ) {
                accessList[i].hasAccess = true;
                accessList[i].grantTime = block.timestamp;
                accessList[i].duration = _duration;

                emit AccessGranted(
                    msg.sender,
                    _doctor,
                    _ipfsHash,
                    block.timestamp,
                    _duration
                );
                return;
            }
        }
        revert("Access request not found");
    }

    function resolveEmergency(address _doctor, string memory _ipfsHash) public {
        uint256 doctorId = walletToDoctorId[_doctor];
        require(doctorId != 0, "Doctor not registered");

        DocumentAccess[] storage accessList = doctorAccessList[doctorId];
        for (uint256 i = 0; i < accessList.length; i++) {
            if (
                accessList[i].patient == msg.sender &&
                keccak256(abi.encodePacked(accessList[i].ipfsHash)) ==
                keccak256(abi.encodePacked(_ipfsHash)) &&
                accessList[i].isEmergency
            ) {
                accessList[i].isResolved = true;
                emit EmergencyResolved(
                    msg.sender,
                    msg.sender,
                    _ipfsHash,
                    block.timestamp
                );
                return;
            }
        }
        revert("Emergency record not found or already resolved");
    }

    function revokeAccess(address _doctor, string memory _ipfsHash) public {
        uint256 doctorId = walletToDoctorId[_doctor];
        require(doctorId != 0, "Doctor not registered");

        DocumentAccess[] storage accessList = doctorAccessList[doctorId];
        for (uint256 i = 0; i < accessList.length; i++) {
            if (
                accessList[i].patient == msg.sender &&
                keccak256(abi.encodePacked(accessList[i].ipfsHash)) ==
                keccak256(abi.encodePacked(_ipfsHash))
            ) {
                accessList[i].hasAccess = false;
                if (accessList[i].isEmergency) {
                    accessList[i].isResolved = true;
                }
                emit AccessRevoked(
                    msg.sender,
                    _doctor,
                    _ipfsHash,
                    block.timestamp
                );
                return;
            }
        }
        revert("Access record not found");
    }

    // --- GETTERS ---
    function getAccessList() public view returns (DocumentAccess[] memory) {
        uint256 doctorId = walletToDoctorId[msg.sender];
        require(doctorId != 0, "Doctor not registered");
        return doctorAccessList[doctorId];
    }

    function getPatients() public view returns (DoctorDetails[] memory) {
        uint256 doctorId = walletToDoctorId[msg.sender];
        require(doctorId != 0, "Doctor not registered");

        DocumentAccess[] memory accessList = doctorAccessList[doctorId];
        DoctorDetails[] memory patients = new DoctorDetails[](
            accessList.length
        );
        uint256 count = 0;

        for (uint256 i = 0; i < accessList.length; i++) {
            if (accessList[i].hasAccess) {
                patients[count] = doctors[doctorId];
                count++;
            }
        }

        return patients;
    }

    function doctorExists(address walletAddress) public view returns (bool) {
        return walletToDoctorId[walletAddress] != 0;
    }

    function getAllDoctors() public view returns (DoctorDetails[] memory) {
        uint256 total = doctorIdCounter;
        DoctorDetails[] memory list = new DoctorDetails[](total);

        for (uint256 i = 0; i < total; i++) {
            list[i] = doctors[i + 1];
        }

        return list;
    }

    function getDoctorsBySpecialization(string calldata _specialization) public view returns (DoctorDetails[] memory) {
        uint256 total = doctorIdCounter;
        uint256 count = 0;
        for (uint256 i = 1; i <= total; i++) {
            if (keccak256(abi.encodePacked(doctors[i].specialization)) == keccak256(abi.encodePacked(_specialization))) {
                count++;
            }
        }

        DoctorDetails[] memory result = new DoctorDetails[](count);
        uint256 idx = 0;
        for (uint256 i = 1; i <= total; i++) {
            if (keccak256(abi.encodePacked(doctors[i].specialization)) == keccak256(abi.encodePacked(_specialization))) {
                result[idx] = doctors[i];
                idx++;
            }
        }
        return result;
    }

    function searchDoctors(string calldata _query) public view returns (DoctorDetails[] memory) {
        uint256 total = doctorIdCounter;
        uint256 count = 0;

        for (uint256 i = 1; i <= total; i++) {
            DoctorDetails memory d = doctors[i];
            if (keccak256(abi.encodePacked(d.name)).length >= keccak256(abi.encodePacked(_query)).length ||
                keccak256(abi.encodePacked(d.specialization)).length >= keccak256(abi.encodePacked(_query)).length) {
                count++;
            }
        }

        DoctorDetails[] memory result = new DoctorDetails[](count);
        uint256 idx = 0;
        for (uint256 i = 1; i <= total; i++) {
            DoctorDetails memory d = doctors[i];
            bytes32 nameHash = keccak256(abi.encodePacked(d.name));
            bytes32 specHash = keccak256(abi.encodePacked(d.specialization));
            bytes32 queryHash = keccak256(abi.encodePacked(_query));
            if (containsSubstring(nameHash, queryHash) || containsSubstring(specHash, queryHash)) {
                result[idx] = d;
                idx++;
            }
        }
        return result;
    }

    function containsSubstring(bytes32 _source, bytes32 _search) internal pure returns (bool) {
        if (_source.length < _search.length) return false;
        bytes32 mask = bytes32((1 << (8 * _search.length)) - 1);
        for (uint256 i = 0; i <= 32 - _search.length; i++) {
            if ((_source >> (i * 8)) == (_search >> (i * 8))) return true;
        }
        return false;
    }

    function cleanupExpiredAccess(uint256 _doctorId) public returns (uint256 cleanedCount) {
        DocumentAccess[] storage accessList = doctorAccessList[_doctorId];
        uint256 count = 0;
        uint256 removedCount = 0;

        for (uint256 i = 0; i < accessList.length; i++) {
            DocumentAccess storage doc = accessList[i];
            if (doc.hasAccess && !doc.isResolved && doc.grantTime + doc.duration <= block.timestamp) {
                doc.hasAccess = false;
                removedCount++;
            }
        }

        return removedCount;
    }

    function cleanupExpiredAccessForAll() public returns (uint256 totalCleaned) {
        totalCleaned = 0;

        for (uint256 i = 1; i <= doctorIdCounter; i++) {
            DocumentAccess[] storage accessList = doctorAccessList[i];
            for (uint256 j = 0; j < accessList.length; j++) {
                DocumentAccess storage doc = accessList[j];
                if (doc.hasAccess && !doc.isResolved && doc.grantTime + doc.duration <= block.timestamp) {
                    doc.hasAccess = false;
                    totalCleaned++;
                }
            }
        }

        return totalCleaned;
    }

    function getExpiredAccessCount(uint256 _doctorId) public view returns (uint256 count) {
        DocumentAccess[] storage accessList = doctorAccessList[_doctorId];

        for (uint256 i = 0; i < accessList.length; i++) {
            DocumentAccess storage doc = accessList[i];
            if (doc.hasAccess && !doc.isResolved && doc.grantTime + doc.duration <= block.timestamp) {
                count++;
            }
        }

        return count;
    }

    function isAccessExpired(uint256 _doctorId, address _patient) public view returns (bool) {
        DocumentAccess[] storage accessList = doctorAccessList[_doctorId];

        for (uint256 i = 0; i < accessList.length; i++) {
            DocumentAccess storage doc = accessList[i];
            if (doc.patient == _patient && doc.hasAccess) {
                return doc.grantTime + doc.duration <= block.timestamp;
            }
        }

        return true;
    }

    // --- PAUSE FUNCTIONS ---
    function pauseContract() public onlyRole(ADMIN_ROLE) {
        _pause();
    }

    function unpauseContract() public onlyRole(ADMIN_ROLE) {
        _unpause();
    }

    // --- ACCESS CONTROL HELPERS ---
    function grantDoctorRole(address _doctor) public onlyRole(ADMIN_ROLE) {
        grantRole(DOCTOR_ROLE, _doctor);
    }

    function revokeDoctorRole(address _doctor) public onlyRole(ADMIN_ROLE) {
        revokeRole(DOCTOR_ROLE, _doctor);
    }

    function isDoctorRole(address _account) public view returns (bool) {
        return hasRole(DOCTOR_ROLE, _account);
    }
}
